module RefModule(clk, reset, set, d, q, qn);input clk, reset, set, d;
output q, qn;
reg q, qn;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or negedge set or posedge dbg_halt) begin
    if (!reset) begin
        q <= 0;
        qn <= 1;
    end else if (!set) begin
        q <= 1;
        qn <= 0;
    end else begin
        q <= d;
        qn <= ~d;
    end
end

endmodule
